export const name = "repo";
export const version = "0.1.0";
export const description = "";

export function getIdentity() {
  return { name, version, description };
}

export function slugify(input) {
  const s = toStr(input);
  if (!s) return "";
  // Normalize and remove combining marks (diacritics)
  const normalized = s.normalize("NFKD").replace(/\p{Mn}+/gu, "");
  // Replace non letters/numbers with hyphens, keep ASCII letters/numbers
  const slug = normalized
    .toLowerCase()
    .replace(/[^\p{L}\p{N}]+/gu, "-")
    .replace(/^-+|-+$/g, "")
    .replace(/-+/g, "-");
  return slug;
}

export function truncate(input, maxLength, suffix = "…") {
  const s = toStr(input);
  if (!s) return "";
  const len = Number(maxLength) || 0;
  if (len <= 0) return "";
  if (s.length <= len) return s;
  const allowed = Math.max(0, len - suffix.length);
  // Find last whitespace within allowed
  const slice = s.slice(0, allowed + 1);
  const lastSpace = slice.lastIndexOf(" ");
  if (lastSpace > 0) {
    return s.slice(0, lastSpace).replace(/\s+$/g, "") + suffix;
  }
  // No safe break found — hard cut
  return s.slice(0, allowed) + suffix;
}

export function camelCase(input) {
  const s = toStr(input);
  if (!s) return "";
  const parts = s
    .split(/[^\p{L}\p{N}]+/u)
    .filter(Boolean)
    .map((p) => p.toLowerCase());
  if (parts.length === 0) return "";
  const first = parts.shift();
  const rest = parts.map((p) => p.charAt(0).toUpperCase() + p.slice(1));
  return [first, ...rest].join("");
}

export function kebabCase(input) {
  const s = toStr(input);
  if (!s) return "";
  // Insert hyphen between camelCase boundaries
  let out = s.replace(/([a-z0-9])([A-Z])/g, "$1-$2");
  // Normalize and remove diacritics
  out = out.normalize("NFKD").replace(/\p{Mn}+/gu, "");
  out = out
    .replace(/[^\p{L}\p{N}]+/gu, "-")
    .replace(/^-+|-+$/g, "")
    .replace(/-+/g, "-")
    .toLowerCase();
  return out;
}

export function titleCase(input) {
  const s = toStr(input);
  if (!s) return "";
  return s
    .split(/(\s|-|_)+/)
    .map((chunk) => {
      if (!chunk.match(/[\p{L}\p{N}]/u)) return chunk;
      return chunk.charAt(0).toUpperCase() + chunk.slice(1).toLowerCase();
    })
    .join("");
}

export function wordWrap(input, width = 80) {
  const s = toStr(input);
  if (!s) return "";
  const w = Math.max(1, Number(width) || 1);
  const words = s.split(/\s+/);
  const lines = [];
  let current = "";
  for (const word of words) {
    if (current === "") {
      if (word.length > w) {
        // Single long word — put on its own line
        lines.push(word);
      } else {
        current = word;
      }
    } else {
      if (current.length + 1 + word.length <= w) {
        current = current + " " + word;
      } else {
        lines.push(current);
        if (word.length > w) {
          lines.push(word);
          current = "";
        } else {
          current = word;
        }
      }
    }
  }
  if (current) lines.push(current);
  return lines.join("\n");
}

export function stripHtml(input) {
  const s = toStr(input);
  if (!s) return "";
  // Remove tags
  let out = s.replace(/<[^>]*>/g, "");
  // Decode named entities (common set)
  const named = {
    nbsp: " ",
    amp: "&",
    lt: "<",
    gt: ">",
    quot: '"',
    apos: "'",
  };
  out = out.replace(/&([a-zA-Z]+);/g, (m, name) => {
    if (Object.prototype.hasOwnProperty.call(named, name)) return named[name];
    return m;
  });
  // Decode numeric entities
  out = out.replace(/&#(\d+);/g, (m, num) => String.fromCharCode(Number(num)));
  out = out.replace(/&#x([0-9a-fA-F]+);/g, (m, hex) => String.fromCharCode(parseInt(hex, 16)));
  return out;
}

export function escapeRegex(input) {
  const s = toStr(input);
  if (!s) return "";
  return s.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

export function pluralize(input) {
  const s = toStr(input);
  if (!s) return "";
  // preserve original case as much as possible by working on lower-case and mapping
  const lower = s.toLowerCase();
  if (/(s|x|z|ch|sh)$/i.test(lower)) return s + "es";
  if (/[aeiou]y$/i.test(lower)) return s + "s";
  if (/y$/i.test(lower)) return s.slice(0, -1) + "ies";
  if (/(?:fe)$/i.test(lower)) return s.slice(0, -2) + "ves";
  if (/f$/i.test(lower)) return s.slice(0, -1) + "ves";
  return s + "s";
}

export function levenshtein(a, b) {
  const sa = Array.from(a == null ? "" : String(a));
  const sb = Array.from(b == null ? "" : String(b));
  const n = sa.length;
  const m = sb.length;
  if (n === 0) return m;
  if (m === 0) return n;
  const v0 = new Array(m + 1).fill(0);
  const v1 = new Array(m + 1).fill(0);
  for (let j = 0; j <= m; j++) v0[j] = j;
  for (let i = 0; i < n; i++) {
    v1[0] = i + 1;
    for (let j = 0; j < m; j++) {
      const cost = sa[i] === sb[j] ? 0 : 1;
      v1[j + 1] = Math.min(v1[j] + 1, v0[j + 1] + 1, v0[j] + cost);
    }
    for (let j = 0; j <= m; j++) v0[j] = v1[j];
  }
  return v1[m];
}
